"""Recursively print files whose contents match a regular expression."""

import argparse
import re
from collections.abc import Iterator
from pathlib import Path
from typing import Pattern


def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(
        description="Search files below ROOT for a regular expression."
    )
    parser.add_argument("root", type=Path, help="directory to search")
    parser.add_argument("--pattern", required=True, help="regular expression to find")
    return parser.parse_args()


def compile_pattern(value: str) -> Pattern[str]:
    try:
        return re.compile(value)
    except re.error as error:
        raise SystemExit(f"invalid regular expression: {error}") from error


def iter_files(root: Path) -> Iterator[Path]:
    if root.is_file():
        yield root
    elif root.is_dir():
        yield from (path for path in root.rglob("*") if path.is_file())
    else:
        raise SystemExit(f"root does not exist: {root}")


def file_matches(path: Path, pattern: Pattern[str]) -> bool:
    try:
        with path.open("r", encoding="utf-8", errors="ignore") as file:
            return any(pattern.search(line) for line in file)
    except OSError:
        return False


def matching_files(root: Path, pattern: Pattern[str]) -> Iterator[Path]:
    for path in iter_files(root):
        if file_matches(path, pattern):
            yield path


def main() -> None:
    args = parse_args()
    pattern = compile_pattern(args.pattern)
    for path in matching_files(args.root, pattern):
        print(path)


if __name__ == "__main__":
    main()

