"""Recursively print files whose contents match a regular expression."""

import argparse
import re
from collections.abc import Iterable
from pathlib import Path


def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(
        description="Print paths of files containing a regex match."
    )
    parser.add_argument("root", type=Path, help="directory (or file) to search")
    parser.add_argument("--pattern", required=True, help="regular expression to find")
    return parser.parse_args()


def iter_files(root: Path) -> Iterable[Path]:
    if root.is_file():
        yield root
    elif root.is_dir():
        yield from (path for path in root.rglob("*") if path.is_file())
    else:
        raise FileNotFoundError(f"root does not exist: {root}")


def file_matches(path: Path, pattern: re.Pattern[str]) -> bool:
    try:
        with path.open("r", encoding="utf-8", errors="replace") as file:
            return any(pattern.search(line) for line in file)
    except OSError:
        return False


def matching_files(root: Path, pattern: re.Pattern[str]) -> Iterable[Path]:
    for path in iter_files(root):
        if file_matches(path, pattern):
            yield path


def main() -> None:
    args = parse_args()
    try:
        pattern = re.compile(args.pattern)
        for path in matching_files(args.root, pattern):
            print(path)
    except (re.error, FileNotFoundError) as error:
        raise SystemExit(str(error)) from error


if __name__ == "__main__":
    main()

