"""Recursively search file contents for a regular expression."""

import argparse
import re
from pathlib import Path
from typing import Pattern


def file_matches(path: Path, pattern: Pattern[str]) -> bool:
    """Return whether *pattern* occurs in a text file.

    Files which cannot be read are ignored so that one inaccessible entry does
    not prevent the rest of a directory tree from being searched.
    """
    try:
        with path.open("r", encoding="utf-8", errors="replace") as stream:
            return any(pattern.search(line) for line in stream)
    except (OSError, UnicodeError):
        return False


def search(root: Path, pattern: Pattern[str]):
    """Yield matching file paths recursively beneath *root*."""
    candidates = (root,) if root.is_file() else root.rglob("*")
    for path in candidates:
        if path.is_file() and file_matches(path, pattern):
            yield path


def main() -> None:
    parser = argparse.ArgumentParser(
        description="Recursively print files whose contents match a regex."
    )
    parser.add_argument("root", type=Path)
    parser.add_argument("--pattern", required=True, help="regular expression to search for")
    args = parser.parse_args()

    try:
        pattern = re.compile(args.pattern)
    except re.error as exc:
        parser.error(f"invalid regular expression: {exc}")

    if not args.root.exists():
        parser.error(f"root does not exist: {args.root}")

    for path in search(args.root, pattern):
        print(path)


if __name__ == "__main__":
    main()

