"""Recursively search text files for one or more regular expressions."""

import argparse
import fnmatch
import os
import re
import sys
from pathlib import Path
from typing import Iterable, Iterator, Optional, Sequence


LANGUAGE_EXTENSIONS = {
    "c": {".c", ".h"},
    "cpp": {".cc", ".cpp", ".cxx", ".h", ".hh", ".hpp", ".hxx"},
    "c++": {".cc", ".cpp", ".cxx", ".h", ".hh", ".hpp", ".hxx"},
    "csharp": {".cs"}, "go": {".go"}, "html": {".htm", ".html"},
    "java": {".java"}, "javascript": {".js", ".jsx", ".mjs", ".cjs"},
    "js": {".js", ".jsx", ".mjs", ".cjs"}, "json": {".json"},
    "kotlin": {".kt", ".kts"}, "markdown": {".md", ".markdown"},
    "perl": {".pl", ".pm"}, "php": {".php"}, "python": {".py", ".pyw"},
    "py": {".py", ".pyw"}, "ruby": {".rb"}, "rust": {".rs"},
    "shell": {".sh", ".bash", ".zsh"}, "sql": {".sql"},
    "swift": {".swift"}, "typescript": {".ts", ".tsx", ".mts", ".cts"},
    "ts": {".ts", ".tsx", ".mts", ".cts"}, "xml": {".xml"},
    "yaml": {".yaml", ".yml"},
}


def comma_values(values: Optional[Iterable[str]]) -> list[str]:
    return [part.strip() for value in (values or []) for part in value.split(",") if part.strip()]


def parse_languages(values: Optional[Iterable[str]]) -> set[str]:
    extensions: set[str] = set()
    for language in comma_values(values):
        language = language.lower()
        extensions.update(LANGUAGE_EXTENSIONS.get(
            language, {language if language.startswith(".") else "." + language}
        ))
    return extensions


def iter_files(root: Path, follow_symlinks: bool) -> Iterator[Path]:
    if root.is_file():
        if follow_symlinks or not root.is_symlink():
            yield root
        return
    for directory, dirs, files in os.walk(root, followlinks=follow_symlinks):
        base = Path(directory)
        if not follow_symlinks:
            dirs[:] = [name for name in dirs if not (base / name).is_symlink()]
        for name in files:
            path = base / name
            if follow_symlinks or not path.is_symlink():
                yield path


def excluded(path: Path, root: Path, globs: Sequence[str]) -> bool:
    try:
        relative = path.relative_to(root).as_posix()
    except ValueError:
        relative = path.name
    return any(fnmatch.fnmatchcase(relative, glob) or fnmatch.fnmatchcase(path.name, glob)
               for glob in globs)


def read_text(path: Path, max_bytes: Optional[int]) -> Optional[str]:
    try:
        if max_bytes is not None and path.stat().st_size > max_bytes:
            return None
        data = path.read_bytes()
    except OSError:
        return None
    if b"\0" in data:
        return None
    return data.decode("utf-8", errors="replace")


def highlight(line: str, patterns: Sequence[re.Pattern[str]], enabled: bool) -> str:
    if not enabled:
        return line
    spans = sorted((m.start(), m.end()) for regex in patterns for m in regex.finditer(line)
                   if m.end() > m.start())
    if not spans:
        return line
    merged: list[list[int]] = []
    for start, end in spans:
        if merged and start <= merged[-1][1]:
            merged[-1][1] = max(merged[-1][1], end)
        else:
            merged.append([start, end])
    result, position = [], 0
    for start, end in merged:
        result.extend((line[position:start], "\033[31m", line[start:end], "\033[0m"))
        position = end
    result.append(line[position:])
    return "".join(result)


def print_line_matches(path: Path, text: str, patterns: Sequence[re.Pattern[str]],
                       context: int, color: bool) -> None:
    lines = text.splitlines()
    matched = [index for index, line in enumerate(lines)
               if any(regex.search(line) for regex in patterns)]
    selected = {index for match in matched
                for index in range(max(0, match - context), min(len(lines), match + context + 1))}
    previous = -2
    for index in sorted(selected):
        if previous >= 0 and index > previous + 1:
            print("--")
        is_match = index in matched
        separator = ":" if is_match else "-"
        content = highlight(lines[index], patterns, color and is_match)
        print(f"{path}{separator}{index + 1}{separator}{content}")
        previous = index


def non_negative(value: str) -> int:
    try:
        number = int(value)
    except ValueError as error:
        raise argparse.ArgumentTypeError("must be an integer") from error
    if number < 0:
        raise argparse.ArgumentTypeError("must be non-negative")
    return number


def main() -> None:
    parser = argparse.ArgumentParser()
    parser.add_argument("root", type=Path)
    group = parser.add_mutually_exclusive_group(required=True)
    group.add_argument("--pattern", help="regular expression to search for")
    group.add_argument("--patterns", nargs="+", metavar="PATTERN",
                       help="regular expressions; a line matching any one is selected")
    parser.add_argument("--langs", action="append", metavar="LANG[,LANG...]", default=[])
    parser.add_argument("--exclude-globs", action="append", metavar="GLOB[,GLOB...]", default=[])
    parser.add_argument("--max-bytes", type=non_negative)
    parser.add_argument("--follow-symlinks", action="store_true")
    parser.add_argument("--line-mode", action="store_true",
                        help="print matching lines instead of only file names")
    parser.add_argument("-C", "--context", type=non_negative, default=0, metavar="N",
                        help="show N lines of context around matches (implies --line-mode)")
    parser.add_argument("--color", choices=("auto", "always", "never"), default="auto",
                        help="color matching text in line mode")
