"""Search files below a root for lines matching a regular expression."""

import argparse
import fnmatch
import os
import re
from pathlib import Path
from typing import Iterable, Iterator, Optional, Set


def parse_csv_values(values: Optional[Iterable[str]]) -> list[str]:
    """Expand repeated, comma-separated command-line values."""
    if not values:
        return []
    return [item.strip() for value in values for item in value.split(",") if item.strip()]


def parse_langs(values: Optional[Iterable[str]]) -> Optional[Set[str]]:
    """Turn repeated/comma-separated language values into file extensions."""
    if not values:
        return None
    return {value.lower().lstrip(".") for value in parse_csv_values(values)}


def matches_language(path: Path, langs: Optional[Set[str]]) -> bool:
    return langs is None or path.suffix.lower().lstrip(".") in langs


def is_excluded(relative_path: Path, globs: Iterable[str]) -> bool:
    """Return whether a root-relative path matches an exclusion glob."""
    path = relative_path.as_posix()
    return any(
        fnmatch.fnmatchcase(path, pattern)
        or fnmatch.fnmatchcase(relative_path.name, pattern)
        for pattern in globs
    )


def iter_files(root: Path, follow_symlinks: bool) -> Iterator[Path]:
    """Yield files under root, following symbolic links only when requested."""
    if root.is_symlink() and not follow_symlinks:
        return
    if root.is_file():
        yield root
        return

    for directory, dirnames, filenames in os.walk(root, followlinks=follow_symlinks):
        directory_path = Path(directory)
        if not follow_symlinks:
            dirnames[:] = [
                name for name in dirnames if not (directory_path / name).is_symlink()
            ]
        for name in filenames:
            path = directory_path / name
            if follow_symlinks or not path.is_symlink():
                yield path


def is_match(path: Path, regex: re.Pattern[str], max_bytes: Optional[int]) -> bool:
    """Return whether an eligible, non-binary file contains a matching line."""
    try:
        if max_bytes is not None and path.stat().st_size > max_bytes:
            return False
        data = path.read_bytes()
    except OSError:
        return False

    if b"\x00" in data:
        return False

    text = data.decode("utf-8", errors="ignore")
    return any(regex.search(line) for line in text.splitlines())


def non_negative_int(value: str) -> int:
    try:
        result = int(value)
    except ValueError as error:
        raise argparse.ArgumentTypeError("must be an integer") from error
    if result < 0:
        raise argparse.ArgumentTypeError("must be non-negative")
    return result


def main() -> None:
    ap = argparse.ArgumentParser()
    ap.add_argument("root")
    ap.add_argument("--pattern", required=True)
    ap.add_argument(
        "--langs",
        action="append",
        metavar="EXT[,EXT...]",
        help="only search files with these extensions (comma-separated; may repeat)",
    )
    ap.add_argument(
        "--exclude-globs",
        action="append",
        metavar="GLOB[,GLOB...]",
        help="exclude root-relative paths matching these globs (may repeat)",
    )
    ap.add_argument(
        "--max-bytes",
        type=non_negative_int,
        help="skip files larger than this many bytes",
    )
    ap.add_argument(
        "--follow-symlinks",
        action="store_true",
        help="follow symbolic links (disabled by default)",
    )
    args = ap.parse_args()

    try:
        regex = re.compile(args.pattern)
    except re.error as error:
        ap.error(f"invalid regular expression: {error}")

    root = Path(args.root)
    if not root.exists():
        ap.error(f"root does not exist: {root}")

    langs = parse_langs(args.langs)
    exclude_globs = parse_csv_values(args.exclude_globs)
    paths = sorted(iter_files(root, args.follow_symlinks), key=lambda path: str(path))
    for path in paths:
        try:
            relative_path = path.relative_to(root) if root.is_dir() else Path(path.name)
        except ValueError:
            relative_path = path
        if (
            not is_excluded(relative_path, exclude_globs)
            and matches_language(path, langs)
            and is_match(path, regex, args.max_bytes)
        ):
            print(path)


if __name__ == "__main__":
    main()

