"""Recursively search text files for one or more regular expressions."""

import argparse
import fnmatch
import os
import re
import sys
from pathlib import Path
from typing import Iterable, Iterator, Optional, Pattern, Sequence, Set


RED = "\033[31m"
RESET = "\033[0m"


def parse_csv_values(values: Optional[Iterable[str]]) -> list[str]:
    """Expand repeated, comma-separated command-line values."""
    if not values:
        return []
    return [item.strip() for value in values for item in value.split(",") if item.strip()]


def parse_langs(values: Optional[Iterable[str]]) -> Optional[Set[str]]:
    if not values:
        return None
    return {value.lower().lstrip(".") for value in parse_csv_values(values)}


def matches_language(path: Path, langs: Optional[Set[str]]) -> bool:
    return langs is None or path.suffix.lower().lstrip(".") in langs


def is_excluded(relative_path: Path, globs: Iterable[str]) -> bool:
    path = relative_path.as_posix()
    return any(
        fnmatch.fnmatchcase(path, pattern)
        or fnmatch.fnmatchcase(relative_path.name, pattern)
        for pattern in globs
    )


def iter_files(root: Path, follow_symlinks: bool) -> Iterator[Path]:
    if root.is_symlink() and not follow_symlinks:
        return
    if root.is_file():
        yield root
        return
    for directory, dirnames, filenames in os.walk(root, followlinks=follow_symlinks):
        base = Path(directory)
        if not follow_symlinks:
            dirnames[:] = [name for name in dirnames if not (base / name).is_symlink()]
        dirnames.sort()
        for name in sorted(filenames):
            path = base / name
            if follow_symlinks or not path.is_symlink():
                yield path


def non_negative_int(value: str) -> int:
    try:
        number = int(value)
    except ValueError as exc:
        raise argparse.ArgumentTypeError("must be an integer") from exc
    if number < 0:
        raise argparse.ArgumentTypeError("must be non-negative")
    return number


def read_text(path: Path, max_bytes: Optional[int]) -> Optional[str]:
    try:
        if max_bytes is not None and path.stat().st_size > max_bytes:
            return None
        data = path.read_bytes()
    except OSError:
        return None
    if b"\x00" in data:
        return None
    return data.decode("utf-8", errors="ignore")


def line_matches(line: str, regexes: Sequence[Pattern[str]]) -> bool:
    return any(regex.search(line) for regex in regexes)


def color_matches(line: str, regexes: Sequence[Pattern[str]]) -> str:
    """Color the union of matches without allowing escape sequences to overlap."""
    spans = sorted(
        (match.start(), match.end())
        for regex in regexes
        for match in regex.finditer(line)
        if match.end() > match.start()
    )
    if not spans:
        return line
    merged: list[list[int]] = []
    for start, end in spans:
        if merged and start <= merged[-1][1]:
            merged[-1][1] = max(merged[-1][1], end)
        else:
            merged.append([start, end])
    pieces: list[str] = []
    cursor = 0
    for start, end in merged:
        pieces.extend((line[cursor:start], RED, line[start:end], RESET))
        cursor = end
    pieces.append(line[cursor:])
    return "".join(pieces)


def display_path(path: Path, root: Path) -> str:
    if root.is_file():
        return str(path)
    try:
        return path.relative_to(root).as_posix()
    except ValueError:
        return str(path)


def emit_lines(
    name: str,
    lines: Sequence[str],
    matches: Sequence[int],
    context: int,
    color: bool,
    regexes: Sequence[Pattern[str]],
) -> None:
    wanted: set[int] = set()
    for index in matches:
        wanted.update(range(max(0, index - context), min(len(lines), index + context + 1)))
    previous: Optional[int] = None
    match_set = set(matches)
    for index in sorted(wanted):
        if previous is not None and index > previous + 1:
            print("--")
        marker = ":" if index in match_set else "-"
        text = color_matches(lines[index], regexes) if color and index in match_set else lines[index]
        print(f"{name}{marker}{index + 1}{marker}{text}")
        previous = index


def build_parser() -> argparse.ArgumentParser:
    parser = argparse.ArgumentParser()
    parser.add_argument("root")
    patterns = parser.add_mutually_exclusive_group(required=True)
    patterns.add_argument("--pattern", help="single regular expression")
    patterns.add_argument(
        "--patterns", action="append", metavar="REGEX[,REGEX...]",
        help="OR-separated regexes (comma-separated; may repeat)",
    )
    parser.add_argument("--langs", action="append", metavar="EXT[,EXT...]")
    parser.add_argument("--exclude-globs", action="append", metavar="GLOB[,GLOB...]")
    parser.add_argument("--max-bytes", type=non_negative_int)
    parser.add_argument("--follow-symlinks", action="store_true")
    parser.add_argument("--line-mode", "--lines", action="store_true", dest="line_mode",
                        help="print matching lines instead of only file names")
    parser.add_argument("--mode", choices=("files", "lines"), help=argparse.SUPPRESS)
    parser.add_argument("--context", "-C", type=non_negative_int, default=0,
                        help="number of context lines before and after each match")
    parser.add_argument("--color", action="store_true", help="color matching text in line mode")
    return parser


def main() -> None:
    parser = build_parser()
    args = parser.parse_args()
    raw_patterns = [args.pattern] if args.pattern is not None else parse_csv_values(args.patterns)
    if not raw_patterns:
        parser.error("--patterns must contain at least one pattern")
    try:
        regexes = [re.compile(pattern) for pattern in raw_patterns]
    except re.error as exc:
        parser.error(f"invalid regular expression: {exc}")

    root = Path(args.root)
    if not root.exists():
        parser.error(f"root does not exist: {root}")
    langs = parse_langs(args.langs)
    exclusions = parse_csv_values(args.exclude_globs)
    line_mode = args.line_mode or args.mode == "lines"

    for path in iter_files(root, args.follow_symlinks):
        try:
            relative = path.relative_to(root) if root.is_dir() else Path(path.name)
        except ValueError:
            relative = path
        if not matches_language(path, langs) or is_excluded(relative, exclusions):
            continue
        text = read_text(path, args.max_bytes)
        if text is None:
            continue
        lines = text.splitlines()
        matching = [i for i, line in enumerate(lines) if line_matches(line, regexes)]
        if not matching:
            continue
        name = display_path(path, root)
        if line_mode:
            emit_lines(name, lines, matching, args.context, args.color, regexes)
        else:
            print(name)


if __name__ == "__main__":
    main()

